            Kokkos::View<char*, Kokkos::MemoryUnmanaged> dst_view(dst_ptr, size * nrecvs);
            Kokkos::deep_copy(dst_view, src_view);
            Kokkos::fence();
            readpos_m += (nrecvs * size);
        }

