    FieldLayout<Dim>::FieldLayout(const mpi::Communicator& communicator)
        : comm(communicator)
        , dLocalDomains_m("local domains (device)", 0)
        , hLocalDomains_m(Kokkos::create_mirror_view(dLocalDomains_m)) {
        for (unsigned int d = 0; d < Dim; ++d) {
            minWidth_m[d] = 0;
