        return gridSizes_m;
    }

    template <typename T, unsigned Dim>
    KOKKOS_INLINE_FUNCTION T Mesh<T, Dim>::getGridsize(size_t dim) const {
        return gridSizes_m[dim];
    }
}  // namespace ippl

