                        // Split to the left and to the right, saving both.
                        domains_c[i].split(copy_c[j], copy_c[j + 1], d);
                    }
                    // Copy back.
                    std::copy(copy_c.begin(), copy_c.begin() + v * 2, domains_c.begin());

