#include "Utility/Timer.h"
#include "Utility/my_auto_ptr.h"

// a simple class used to store timer values
class IpplTimerInfo {
public:
    // typedef for reference to a timer
    typedef unsigned int TimerRef;

    // constructor
    IpplTimerInfo()
        : name("")
        , wallTime(0.0)
        , indx(std::numeric_limits<TimerRef>::max()) {
        clear();
    }

    // destructor
    ~IpplTimerInfo() {}

    // timer operations
    void start() {
        if (!running) {
            running = true;
            t.stop();
            t.clear();
            t.start();
        }
    }

    void stop() {
        if (running) {
            t.stop();
            running = false;
            wallTime += t.elapsed();
        }
    }

    void clear() {
        t.stop();
        t.clear();
        running = false;
    }

    // the IPPL timer that this object manages
    Timer t;

    // the name of this timer
    std::string name;

    // the accumulated time
    double wallTime;

    // is the timer turned on right now?
    bool running;

    // an index value for this timer
    TimerRef indx;
};

